   490→// checkPairs returns the count of strings passed in, and an error if
   491→// the count is not an even number.
   492→func checkPairs(pairs ...string) (int, error) {
   493→	length := len(pairs)
   494→	if length%2 != 0 {
   495→		return length, fmt.Errorf(
